#include <stdio.h>
#include <string.h>

#define MAX_FILES 10
#define MAX_USERS 5

// Permission bits
#define PERM_READ    4
#define PERM_WRITE   2
#define PERM_EXEC    1

// File capability entry
typedef struct {
    int file_id;
    int permissions;  // OR of PERM_READ, PERM_WRITE, PERM_EXEC
} FileCap;

// User capability list
typedef struct {
    char username[20];
    int cap_count;
    FileCap capabilities[MAX_FILES];
} CapabilityList;

// Check if user has required permission
int check_access(CapabilityList *user, int file_id, int required_perm) {
    for (int i = 0; i < user->cap_count; i++) {
        if (user->capabilities[i].file_id == file_id) {
            return (user->capabilities[i].permissions & required_perm) != 0;
        }
    }
    return 0;  // No capability for this file
}

int main() {
    // Create capability list for a user
    CapabilityList user1;
    strcpy(user1.username, "alice");
    user1.cap_count = 2;
    user1.capabilities[0] = (FileCap){1, PERM_READ | PERM_WRITE};
    user1.capabilities[1] = (FileCap){2, PERM_READ};

    // Check access
    if (check_access(&user1, 1, PERM_WRITE)) {
        printf("Access GRANTED: Alice can write to file 1\n");
    } else {
        printf("Access DENIED: Alice cannot write to file 1\n");
    }

    return 0;
}
